"use client";

import { useEffect, useRef, useState } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import {
  getRandomComplete,
  getRandomEncourage,
  triggerShake,
} from "@/lib/learningMessages";
import { markStepDone } from "@/lib/progress";

// ===== 第一层：回顾内容（前 6 步关键操作） =====
const REVIEW_ITEMS = [
  {
    icon: "✋",
    step: "1",
    label: "摸一摸",
    text: "你把彩色纸平均分给了同学",
  },
  {
    icon: "⚖️",
    step: "2",
    label: "比一比",
    text: "口算和估算，整十数除法和普通除法",
  },
  {
    icon: "🔢",
    step: "3",
    label: "数一数",
    text: "用小棒分一分，再用竖式记录",
  },
  {
    icon: "✏️",
    step: "4",
    label: "画一画",
    text: "画条形图帮助理解除法的意义",
  },
  {
    icon: "🔄",
    step: "5",
    label: "变一变",
    text: "用乘法验算除法",
  },
  {
    icon: "🏠",
    step: "6",
    label: "用一用",
    text: "分桃子、摆花盆、分图书",
  },
] as const;

const REVIEW_DURATION = 3000; // 每条 3 秒自动切换

// ===== 第二层：选择选项 =====
const CHOICE_OPTIONS = [
  { key: "A", text: "除法就是把东西平均分" },
  { key: "B", text: "0 不能做除数" },
  { key: "C", text: "余数一定要比除数小" },
] as const;

// ===== 画图画布规格 =====
const CANVAS_COLS = 8;
const CANVAS_ROWS = 4;
const CANVAS_TOTAL = CANVAS_COLS * CANVAS_ROWS;

// ===== 验证动画条目 =====
const VERIFY_ZERO_ITEMS = [
  { expr: "0 ÷ 5 = 0", ok: true, note: "0 除以任何不是 0 的数都等于 0" },
  { expr: "5 ÷ 0 = ？", ok: false, note: "0 不能做除数！" },
] as const;

const VERIFY_REMAINDER_ITEMS = [
  { expr: "17 ÷ 5 = 3···2", ok: true, note: "余数 2 < 除数 5" },
  { expr: "17 ÷ 5 = 3···6", ok: false, note: "余数 6 > 除数 5，换一个试试？" },
] as const;

type Layer = "review" | "express" | "verify" | "card";
type ExpressTab = "fill" | "draw" | "choose";

export default function DiscoverPage() {
  const [layer, setLayer] = useState<Layer>("review");
  const [completeMsg, setCompleteMsg] = useState("");
  useEffect(() => { setCompleteMsg(getRandomComplete()); }, []);

  // ===== 第一层：回顾 =====
  const [reviewIdx, setReviewIdx] = useState(0);
  const reviewDone = reviewIdx >= REVIEW_ITEMS.length;

  useEffect(() => {
    if (layer !== "review") return;
    if (reviewIdx >= REVIEW_ITEMS.length) return;
    const id = setTimeout(() => setReviewIdx((p) => p + 1), REVIEW_DURATION);
    return () => clearTimeout(id);
  }, [layer, reviewIdx]);

  // ===== 第二层：表达发现 =====
  const [tab, setTab] = useState<ExpressTab>("fill");
  const [fillA, setFillA] = useState("");
  const [fillB, setFillB] = useState("");
  const [fillC, setFillC] = useState("");
  const [drawCells, setDrawCells] = useState<boolean[]>(
    Array.from({ length: CANVAS_TOTAL }, () => false)
  );
  const [choice, setChoice] = useState<string | null>(null);
  const [customText, setCustomText] = useState("");

  const drawCount = drawCells.filter(Boolean).length;

  const fillRef = useRef<HTMLDivElement>(null);
  const encourageMsg = useRef(getRandomEncourage());

  const tabValid =
    tab === "fill"
      ? fillA !== "" && fillB !== "" && fillC !== ""
      : tab === "draw"
        ? drawCount > 0
        : choice !== null && (choice !== "D" || customText.trim() !== "");

  const handleFillSubmit = () => {
    if (fillA === "" || fillB === "" || fillC === "") {
      triggerShake(fillRef.current);
      encourageMsg.current = getRandomEncourage();
    }
  };

  const buildExpression = (): string => {
    if (tab === "fill")
      return `我发现：0÷N=${fillA}，余数必须${fillB}除数，商×除数+余数=${fillC}`;
    if (tab === "draw")
      return `我画了 ${drawCount} 个格子表示"平均分"`;
    if (choice === "D") return `我的发现：${customText.trim()}`;
    const opt = CHOICE_OPTIONS.find((o) => o.key === choice);
    return opt ? `我选 ${choice}：${opt.text}` : "";
  };

  // ===== 第三层：验证 =====
  const [expression, setExpression] = useState("");
  const [verifyStep, setVerifyStep] = useState(0);
  // verifyStep: 0=逐条点亮零规律, 1=零规律完成, 2=逐条点亮余数规律, 3=余数规律完成, 4=可进入发现卡
  const [zeroLit, setZeroLit] = useState<boolean[]>(
    Array.from({ length: VERIFY_ZERO_ITEMS.length }, () => false)
  );
  const [remainderLit, setRemainderLit] = useState<boolean[]>(
    Array.from({ length: VERIFY_REMAINDER_ITEMS.length }, () => false)
  );

  useEffect(() => {
    if (layer !== "verify") return;

    if (verifyStep === 0) {
      // 逐条点亮零规律
      let i = 0;
      const id = setInterval(() => {
        i += 1;
        setZeroLit((prev) => {
          const next = [...prev];
          next[i - 1] = true;
          return next;
        });
        if (i >= VERIFY_ZERO_ITEMS.length) {
          clearInterval(id);
          setTimeout(() => setVerifyStep(1), 800);
        }
      }, 900);
      return () => clearInterval(id);
    }

    if (verifyStep === 2) {
      // 逐条点亮余数规律
      let i = 0;
      const id = setInterval(() => {
        i += 1;
        setRemainderLit((prev) => {
          const next = [...prev];
          next[i - 1] = true;
          return next;
        });
        if (i >= VERIFY_REMAINDER_ITEMS.length) {
          clearInterval(id);
          setTimeout(() => setVerifyStep(3), 800);
          setTimeout(() => setVerifyStep(4), 2400);
        }
      }, 900);
      return () => clearInterval(id);
    }
  }, [layer, verifyStep]);

  // 从零规律完成自动进入余数规律
  useEffect(() => {
    if (layer !== "verify") return;
    if (verifyStep === 1) {
      const id = setTimeout(() => setVerifyStep(2), 1500);
      return () => clearTimeout(id);
    }
  }, [layer, verifyStep]);

  const goVerify = () => {
    setExpression(buildExpression());
    setZeroLit(Array.from({ length: VERIFY_ZERO_ITEMS.length }, () => false));
    setRemainderLit(
      Array.from({ length: VERIFY_REMAINDER_ITEMS.length }, () => false)
    );
    setVerifyStep(0);
    setLayer("verify");
  };

  const replay = () => {
    setLayer("review");
    setReviewIdx(0);
    setTab("fill");
    setFillA("");
    setFillB("");
    setFillC("");
    setDrawCells(Array.from({ length: CANVAS_TOTAL }, () => false));
    setChoice(null);
    setCustomText("");
    setExpression("");
    setVerifyStep(0);
    setZeroLit(Array.from({ length: VERIFY_ZERO_ITEMS.length }, () => false));
    setRemainderLit(
      Array.from({ length: VERIFY_REMAINDER_ITEMS.length }, () => false)
    );
  };

  return (
    <StepShell topicId="division" stepId="discover">
      <div className="space-y-6">
        {/* ===== 第一层：回顾 ===== */}
        {layer === "review" && (
          <div className="space-y-6">
            <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
              <h2 className="text-center text-lg font-semibold text-[var(--text)]">
                我们一起走过的路
              </h2>
              <p className="mt-1 text-center text-sm text-[var(--text-secondary)]">
                回顾这 6 步，你做了好多事！
              </p>

              <div className="mt-6 flex min-h-[150px] items-center justify-center">
                {reviewIdx < REVIEW_ITEMS.length ? (
                  <div
                    key={reviewIdx}
                    className="animate-float-in flex flex-col items-center text-center"
                  >
                    <div className="text-5xl animate-bounce-soft">
                      {REVIEW_ITEMS[reviewIdx].icon}
                    </div>
                    <p className="mt-3 text-lg font-medium text-[var(--text)]">
                      {REVIEW_ITEMS[reviewIdx].step}.{" "}
                      {REVIEW_ITEMS[reviewIdx].label}
                    </p>
                    <p className="mt-1 text-[var(--text-secondary)]">
                      {REVIEW_ITEMS[reviewIdx].text}
                    </p>
                  </div>
                ) : (
                  <div className="animate-float-in flex flex-col items-center text-center">
                    <div className="text-4xl">🌟</div>
                    <p className="mt-2 text-lg font-semibold text-[var(--text)]">
                      6 步走完啦！
                    </p>
                  </div>
                )}
              </div>

              {/* 进度点 */}
              <div className="mt-4 flex justify-center gap-2">
                {REVIEW_ITEMS.map((it, i) => (
                  <div
                    key={it.step}
                    className={`h-2 w-2 rounded-full transition-colors ${
                      i < reviewIdx
                        ? "bg-[var(--signal-confirmed)]"
                        : i === reviewIdx
                          ? "bg-[var(--signal-focus)]"
                          : "bg-[var(--signal-pending)]"
                    }`}
                  />
                ))}
              </div>
            </section>

            {/* 回顾完成 → 进入表达层 */}
            {reviewDone && (
              <section className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-focus)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
                <div className="text-center">
                  <div className="text-3xl animate-bounce-soft">🎯</div>
                  <p className="mt-3 text-[var(--text)]">
                    你已经走完了除法的全部 6 步探索！
                  </p>
                  <p className="mt-1 text-sm text-[var(--text-secondary)]">
                    说说你发现了什么吧
                  </p>
                </div>
                <div className="mt-6 text-center">
                  <button
                    onClick={() => setLayer("express")}
                    className="rounded-full bg-[var(--signal-confirmed)] px-8 py-3 text-sm font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:-translate-y-0.5 hover:shadow-[var(--shadow-md)]"
                  >
                    说说我的发现 →
                  </button>
                </div>
              </section>
            )}
          </div>
        )}

        {/* ===== 第二层：表达发现（三选一） ===== */}
        {layer === "express" && (
          <div className="space-y-6">
            <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-5 shadow-[var(--shadow-sm)]">
              <h2 className="text-center text-lg font-semibold text-[var(--text)]">
                你发现了什么？
              </h2>
              <p className="mt-1 text-center text-sm text-[var(--text-secondary)]">
                选一种你喜欢的方式表达出来（三选一）
              </p>
            </section>

            {/* 选项卡 */}
            <div className="flex justify-center gap-2">
              {(
                [
                  { key: "fill", icon: "🖊️", label: "填写规律" },
                  { key: "draw", icon: "🎨", label: "画图记录" },
                  { key: "choose", icon: "💬", label: "选择补充" },
                ] as { key: ExpressTab; icon: string; label: string }[]
              ).map((t) => (
                <button
                  key={t.key}
                  onClick={() => setTab(t.key)}
                  className={`rounded-full px-5 py-2 text-sm font-medium transition-all ${
                    tab === t.key
                      ? "bg-[var(--signal-focus)] text-[var(--text)] shadow-[var(--shadow-sm)]"
                      : "bg-[var(--bg-soft)] text-[var(--text-secondary)] hover:bg-[var(--signal-focus)]/30"
                  }`}
                >
                  {t.icon} {t.label}
                </button>
              ))}
            </div>

            {/* 填写规律 */}
            {tab === "fill" && (
              <section
                ref={fillRef}
                className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]"
              >
                <p className="text-center text-[var(--text)]">我发现：</p>
                <div className="mt-4 space-y-4">
                  {/* 第一条规律 */}
                  <div className="flex flex-wrap items-center justify-center gap-2 text-xl font-bold text-[var(--text)]">
                    <span>0 ÷ 任何不是 0 的数 =</span>
                    <input
                      type="text"
                      inputMode="numeric"
                      value={fillA}
                      onChange={(e) =>
                        setFillA(e.target.value.replace(/[^0-9]/g, ""))
                      }
                      className="w-16 rounded-lg border-2 border-[var(--border)] px-3 py-2 text-center text-xl font-bold text-[var(--text)] focus:border-[var(--primary)] focus:outline-none"
                      placeholder="?"
                      autoFocus
                    />
                  </div>
                  {/* 第二条规律 */}
                  <div className="flex flex-wrap items-center justify-center gap-2 text-xl font-bold text-[var(--text)]">
                    <span>余数必须</span>
                    <input
                      type="text"
                      value={fillB}
                      onChange={(e) => setFillB(e.target.value)}
                      className="w-16 rounded-lg border-2 border-[var(--border)] px-3 py-2 text-center text-xl font-bold text-[var(--text)] focus:border-[var(--primary)] focus:outline-none"
                      placeholder="?"
                    />
                    <span>除数</span>
                  </div>
                  {/* 第三条规律 */}
                  <div className="flex flex-wrap items-center justify-center gap-2 text-xl font-bold text-[var(--text)]">
                    <span>商 × 除数 + 余数 =</span>
                    <input
                      type="text"
                      value={fillC}
                      onChange={(e) => setFillC(e.target.value)}
                      className="w-16 rounded-lg border-2 border-[var(--border)] px-3 py-2 text-center text-xl font-bold text-[var(--text)] focus:border-[var(--primary)] focus:outline-none"
                      placeholder="?"
                    />
                  </div>
                </div>
                <p className="mt-4 text-center text-xs text-[var(--text-muted)]">
                  试着把你发现的除法规律填出来
                </p>
              </section>
            )}

            {/* 画图记录 */}
            {tab === "draw" && (
              <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
                <p className="text-center text-sm text-[var(--text-secondary)]">
                  在网格上画一画，表示"平均分"的概念
                </p>
                <div
                  className="mx-auto mt-4 grid w-full max-w-[420px] gap-1.5"
                  style={{ gridTemplateColumns: `repeat(${CANVAS_COLS}, 1fr)` }}
                >
                  {drawCells.map((on, idx) => (
                    <button
                      key={idx}
                      type="button"
                      aria-label={`画布格子 ${idx + 1}`}
                      onClick={() =>
                        setDrawCells((prev) => {
                          const next = [...prev];
                          next[idx] = !next[idx];
                          return next;
                        })
                      }
                      className={`aspect-square rounded-md transition-all duration-150 ${
                        on
                          ? "bg-[var(--signal-confirmed)]"
                          : "border-2 border-dashed border-[var(--signal-pending)] hover:border-[var(--signal-focus)] hover:bg-[var(--signal-focus)]/20"
                      }`}
                    />
                  ))}
                </div>
                <div className="mt-3 flex items-center justify-center gap-3 text-sm text-[var(--text-secondary)]">
                  <span>
                    已画{" "}
                    <span className="font-bold text-[var(--text)]">
                      {drawCount}
                    </span>{" "}
                    格
                  </span>
                  {drawCount > 0 && (
                    <button
                      onClick={() =>
                        setDrawCells(
                          Array.from({ length: CANVAS_TOTAL }, () => false)
                        )
                      }
                      className="text-xs text-[var(--text-muted)] underline"
                    >
                      清空
                    </button>
                  )}
                </div>
              </section>
            )}

            {/* 选择 + 补充 */}
            {tab === "choose" && (
              <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
                <div className="space-y-3">
                  {CHOICE_OPTIONS.map((opt) => (
                    <button
                      key={opt.key}
                      onClick={() => setChoice(opt.key)}
                      className={`flex w-full items-center gap-3 rounded-lg border-2 px-4 py-3 text-left transition-all ${
                        choice === opt.key
                          ? "border-[var(--signal-focus)] bg-[var(--signal-focus)]/20"
                          : "border-[var(--border)] bg-[var(--bg-soft)] hover:border-[var(--signal-focus)]/50"
                      }`}
                    >
                      <span className="flex h-7 w-7 shrink-0 items-center justify-center rounded-full bg-[var(--bg-card)] text-sm font-bold text-[var(--text)]">
                        {opt.key}
                      </span>
                      <span className="text-[var(--text)]">{opt.text}</span>
                    </button>
                  ))}

                  {/* D 自定义 */}
                  <div
                    className={`flex items-center gap-3 rounded-lg border-2 px-4 py-3 transition-all ${
                      choice === "D"
                        ? "border-[var(--signal-focus)] bg-[var(--signal-focus)]/20"
                        : "border-[var(--border)] bg-[var(--bg-soft)]"
                    }`}
                  >
                    <button
                      onClick={() => setChoice("D")}
                      className="flex h-7 w-7 shrink-0 items-center justify-center rounded-full bg-[var(--bg-card)] text-sm font-bold text-[var(--text)]"
                      aria-label="选项 D"
                    >
                      D
                    </button>
                    <input
                      type="text"
                      value={customText}
                      onChange={(e) => {
                        setCustomText(e.target.value);
                        setChoice("D");
                      }}
                      placeholder="我想说…"
                      className="flex-1 bg-transparent text-[var(--text)] placeholder:text-[var(--text-muted)] focus:outline-none"
                    />
                  </div>
                </div>
              </section>
            )}

            {/* 抖动提示 */}
            {!tabValid && tab === "fill" && (
              <p className="text-center text-sm text-[var(--text-muted)]">
                {encourageMsg.current}
              </p>
            )}

            {/* 下一步 */}
            <div className="flex justify-center">
              <button
                onClick={() => {
                  if (tab === "fill" && !tabValid) {
                    handleFillSubmit();
                    return;
                  }
                  goVerify();
                }}
                disabled={!tabValid}
                className="rounded-full bg-[var(--signal-confirmed)] px-8 py-3 text-sm font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:-translate-y-0.5 hover:shadow-[var(--shadow-md)] disabled:cursor-not-allowed disabled:opacity-40 disabled:hover:translate-y-0"
              >
                我发现了 →
              </button>
            </div>
          </div>
        )}

        {/* ===== 第三层：验证规律 ===== */}
        {layer === "verify" && (
          <div className="space-y-6">
            {/* 零的规律 */}
            <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
              <h2 className="text-center text-lg font-semibold text-[var(--text)]">
                验证规律一：0 的秘密
              </h2>
              <p className="mt-1 text-center text-sm text-[var(--text-secondary)]">
                0 在除法里有什么特别的？
              </p>

              <div className="mt-6 space-y-3">
                {VERIFY_ZERO_ITEMS.map((item, idx) => (
                  <div
                    key={idx}
                    className={`flex items-center gap-4 rounded-lg border-2 px-5 py-4 transition-all duration-500 ${
                      zeroLit[idx]
                        ? item.ok
                          ? "border-[var(--signal-success)] bg-[var(--signal-success)]/10"
                          : "border-[var(--signal-shake)] bg-[var(--signal-shake)]/10"
                          : "border-[var(--border)] bg-[var(--bg-soft)] opacity-40"
                    }`}
                  >
                    <span
                      className={`text-2xl transition-all duration-500 ${
                        zeroLit[idx]
                          ? item.ok
                            ? "text-[var(--signal-success)]"
                            : "text-[var(--signal-shake)]"
                          : "text-[var(--text-muted)]"
                      }`}
                    >
                      {zeroLit[idx] ? (item.ok ? "\u2713" : "\u2717") : "○"}
                    </span>
                    <div className="flex-1">
                      <p
                        className={`text-xl font-bold transition-colors duration-500 ${
                          zeroLit[idx]
                            ? item.ok
                              ? "text-[var(--text)]"
                              : "text-[var(--signal-shake)]"
                            : "text-[var(--text-muted)]"
                        }`}
                      >
                        {item.expr}
                      </p>
                      {zeroLit[idx] && (
                        <p
                          className={`mt-1 text-sm animate-float-in ${
                            item.ok
                              ? "text-[var(--signal-success)]"
                              : "text-[var(--signal-shake)]"
                          }`}
                        >
                          {item.note}
                        </p>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            </section>

            {/* 余数规律 */}
            {verifyStep >= 1 && (
              <section
                className={`rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)] transition-opacity duration-500 ${
                  verifyStep >= 2 ? "animate-float-in opacity-100" : "opacity-0"
                }`}
              >
                <h2 className="text-center text-lg font-semibold text-[var(--text)]">
                  验证规律二：余数的规则
                </h2>
                <p className="mt-1 text-center text-sm text-[var(--text-secondary)]">
                  余数和除数之间有什么关系？
                </p>

                <div className="mt-6 space-y-3">
                  {VERIFY_REMAINDER_ITEMS.map((item, idx) => (
                    <div
                      key={idx}
                      className={`flex items-center gap-4 rounded-lg border-2 px-5 py-4 transition-all duration-500 ${
                        remainderLit[idx]
                          ? item.ok
                            ? "border-[var(--signal-success)] bg-[var(--signal-success)]/10"
                            : "border-[var(--signal-shake)] bg-[var(--signal-shake)]/10"
                          : "border-[var(--border)] bg-[var(--bg-soft)] opacity-40"
                      }`}
                    >
                      <span
                        className={`text-2xl transition-all duration-500 ${
                          remainderLit[idx]
                            ? item.ok
                              ? "text-[var(--signal-success)]"
                              : "text-[var(--signal-shake)]"
                            : "text-[var(--text-muted)]"
                        }`}
                      >
                        {remainderLit[idx]
                          ? item.ok
                            ? "\u2713"
                            : "\u2717"
                          : "○"}
                      </span>
                      <div className="flex-1">
                        <p
                          className={`text-xl font-bold transition-colors duration-500 ${
                            remainderLit[idx]
                              ? item.ok
                                ? "text-[var(--text)]"
                                : "text-[var(--signal-shake)]"
                              : "text-[var(--text-muted)]"
                          }`}
                        >
                          {item.expr}
                        </p>
                        {remainderLit[idx] && (
                          <p
                            className={`mt-1 text-sm animate-float-in ${
                              item.ok
                                ? "text-[var(--signal-success)]"
                                : "text-[var(--signal-shake)]"
                            }`}
                          >
                            {item.note}
                          </p>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              </section>
            )}

            {/* 验证完成按钮 */}
            {verifyStep >= 4 && (
              <div className="flex justify-center">
                <button
                  onClick={() => setLayer("card")}
                  className="animate-float-in rounded-full bg-[var(--accent)] px-8 py-3 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:-translate-y-0.5"
                >
                  查看发现卡 →
                </button>
              </div>
            )}
          </div>
        )}

        {/* ===== 第四层：发现卡 ===== */}
        {layer === "card" && (
          <div className="space-y-6">
            {/* 渐变边框发现卡 */}
            <section className="animate-float-in relative overflow-hidden rounded-[var(--radius)] p-[3px] shadow-[var(--shadow-lg)]">
              {/* 渐变边框背景层 */}
              <div
                className="pointer-events-none absolute inset-0 rounded-[var(--radius)]"
                style={{
                  background:
                    "linear-gradient(135deg, var(--accent), var(--primary), var(--accent2), var(--accent3), var(--accent))",
                }}
              />
              {/* 卡片内容层 */}
              <div className="relative rounded-[calc(var(--radius)-3px)] bg-[var(--bg-card)] p-6">
                {/* 卡头 */}
                <div className="flex items-center justify-between border-b border-dashed border-[var(--border)] pb-4">
                  <div className="flex items-center gap-2">
                    <span className="text-2xl">🌟</span>
                    <div>
                      <h3 className="text-lg font-bold text-[var(--text)]">
                        我的除法发现卡
                      </h3>
                      <p className="text-xs text-[var(--text-muted)]">
                        除数是一位数的除法 · 七步探索
                      </p>
                    </div>
                  </div>
                  <span className="rounded-full bg-[var(--signal-focus)] px-3 py-1 text-xs font-bold text-[var(--text)]">
                    完成
                  </span>
                </div>

                {/* 我的表达 */}
                <div className="mt-4">
                  <p className="text-xs font-medium text-[var(--text-muted)]">
                    我的发现
                  </p>
                  <p className="mt-1 rounded-lg bg-[var(--bg-soft)] px-4 py-3 text-[var(--text)]">
                    {expression}
                  </p>
                </div>

                {/* 三个要点 */}
                <div className="mt-4 space-y-2">
                  <p className="text-xs font-medium text-[var(--text-muted)]">
                    除法的三个重要规律
                  </p>
                  <div className="space-y-2 rounded-lg border-2 border-[var(--signal-focus)] bg-[var(--signal-focus)]/10 px-4 py-4">
                    <div className="flex items-start gap-2">
                      <span className="mt-0.5 text-[var(--signal-success)]">
                        &#10003;
                      </span>
                      <p className="text-[var(--text)]">
                        除法就是平均分，把总数分成相等的若干份
                      </p>
                    </div>
                    <div className="flex items-start gap-2">
                      <span className="mt-0.5 text-[var(--signal-success)]">
                        &#10003;
                      </span>
                      <p className="text-[var(--text)]">
                        0 除以任何不是 0 的数都等于 0，但 0 不能做除数
                      </p>
                    </div>
                    <div className="flex items-start gap-2">
                      <span className="mt-0.5 text-[var(--signal-success)]">
                        &#10003;
                      </span>
                      <p className="text-[var(--text)]">
                        余数一定要比除数小
                      </p>
                    </div>
                  </div>
                </div>

                {/* 回顾六步 */}
                <div className="mt-4">
                  <p className="text-xs font-medium text-[var(--text-muted)]">
                    我走过的 6 步
                  </p>
                  <div className="mt-2 flex flex-wrap gap-2">
                    {REVIEW_ITEMS.map((it) => (
                      <span
                        key={it.step}
                        className="inline-flex items-center gap-1 rounded-full bg-[var(--bg-soft)] px-2.5 py-1 text-xs text-[var(--text-secondary)]"
                      >
                        <span>{it.icon}</span>
                        {it.label}
                      </span>
                    ))}
                  </div>
                </div>

                {/* 卡尾 */}
                <div className="mt-5 border-t border-dashed border-[var(--border)] pt-4">
                  <p className="text-center text-[var(--text)]">
                    🎉 你已经完成了除数是一位数的除法的全部学习！
                  </p>
                </div>

                {/* 卡尾信息 */}
                <div className="mt-3 flex items-center justify-between">
                  <span className="text-xs text-[var(--text-muted)]">
                    {completeMsg}
                  </span>
                  <span className="text-xs text-[var(--text-muted)]">
                    🌟 数学好好玩
                  </span>
                </div>
              </div>
            </section>

            <p className="text-center text-xs text-[var(--text-muted)]">
              提示：可以截图保存这张卡片哦
            </p>

            <div className="flex flex-wrap items-center justify-center gap-3">
              <button
                onClick={replay}
                className="rounded-full border border-[var(--border)] bg-[var(--bg-soft)] px-5 py-2 text-sm font-medium text-[var(--text-secondary)] transition-colors hover:bg-[var(--bg-card)]"
              >
                再玩一次
              </button>
              <Link
                href="/learn/division"
                className="rounded-full bg-[var(--signal-confirmed)] px-5 py-2 text-sm font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:-translate-y-0.5"
              >
                回到除法主页
              </Link>
              <Link
                href="/"
                className="rounded-full border border-[var(--border)] bg-[var(--bg-card)] px-5 py-2 text-sm font-medium text-[var(--text-secondary)] transition-colors hover:bg-[var(--bg-soft)]"
              >
                返回首页
              </Link>
            </div>
          </div>
        )}
      </div>
    </StepShell>
  );
}
